CREATE TYPE "OrderStatus" AS ENUM ('PENDING_PAYMENT','RECEIVED','ACCEPTED','COOKING','READY','COLLECTED','CANCELLED');
CREATE TYPE "PaymentMethod" AS ENUM ('ONLINE','PICKUP');
CREATE TYPE "PaymentStatus" AS ENUM ('PENDING','PAID','PAY_AT_PICKUP','REFUNDED');
CREATE TABLE "Settings" ("id" TEXT NOT NULL DEFAULT 'main',"venueName" TEXT NOT NULL,"phone" TEXT NOT NULL,"address" TEXT NOT NULL,"isOrderingOpen" BOOLEAN NOT NULL DEFAULT true,"pickupMinutes" INTEGER NOT NULL DEFAULT 30,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Settings_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Category" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"sortOrder" INTEGER NOT NULL DEFAULT 0,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Category_pkey" PRIMARY KEY ("id"));
CREATE TABLE "MenuItem" ("id" TEXT NOT NULL,"categoryId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT NOT NULL DEFAULT '',"priceCents" INTEGER NOT NULL,"active" BOOLEAN NOT NULL DEFAULT true,"soldOut" BOOLEAN NOT NULL DEFAULT false,"dietary" TEXT[] DEFAULT ARRAY[]::TEXT[],"sortOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "MenuItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Order" ("id" TEXT NOT NULL,"orderNumber" INTEGER NOT NULL,"customerName" TEXT NOT NULL,"customerPhone" TEXT NOT NULL,"customerEmail" TEXT,"pickupTime" TIMESTAMP(3) NOT NULL,"notes" TEXT,"paymentMethod" "PaymentMethod" NOT NULL,"paymentStatus" "PaymentStatus" NOT NULL,"stripeSessionId" TEXT,"status" "OrderStatus" NOT NULL,"subtotalCents" INTEGER NOT NULL,"totalCents" INTEGER NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Order_pkey" PRIMARY KEY ("id"));
CREATE TABLE "OrderLine" ("id" TEXT NOT NULL,"orderId" TEXT NOT NULL,"itemId" TEXT NOT NULL,"name" TEXT NOT NULL,"quantity" INTEGER NOT NULL,"unitPriceCents" INTEGER NOT NULL,"notes" TEXT,CONSTRAINT "OrderLine_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Counter" ("id" TEXT NOT NULL,"value" INTEGER NOT NULL DEFAULT 0,CONSTRAINT "Counter_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "Category_name_key" ON "Category"("name"); CREATE INDEX "MenuItem_categoryId_sortOrder_idx" ON "MenuItem"("categoryId","sortOrder"); CREATE UNIQUE INDEX "Order_orderNumber_key" ON "Order"("orderNumber"); CREATE UNIQUE INDEX "Order_stripeSessionId_key" ON "Order"("stripeSessionId"); CREATE INDEX "Order_status_createdAt_idx" ON "Order"("status","createdAt"); CREATE INDEX "Order_pickupTime_idx" ON "Order"("pickupTime"); CREATE INDEX "OrderLine_orderId_idx" ON "OrderLine"("orderId"); CREATE INDEX "OrderLine_itemId_idx" ON "OrderLine"("itemId");
ALTER TABLE "MenuItem" ADD CONSTRAINT "MenuItem_categoryId_fkey" FOREIGN KEY ("categoryId") REFERENCES "Category"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "OrderLine" ADD CONSTRAINT "OrderLine_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "Order"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "OrderLine" ADD CONSTRAINT "OrderLine_itemId_fkey" FOREIGN KEY ("itemId") REFERENCES "MenuItem"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
